+//! Benchmark BNNS ANE vs Metal BF16 GPU
+//! Compare speed and (ideally) power consumption
+
+const std = @import("std");
+const BF16 = @import("inference/gguf_loader.zig").BF16;
+const bnns_ane = @import("inference/bnns_ane_matmul.zig");
+const metal_bf16 = @import("inference/metal_bf16_matmul.zig");
+const objc = @import("inference/metal/objc.zig");
+
+pub fn main() !void {
+    var gpa = std.heap.GeneralPurposeAllocator(.{}){};
+    defer _ = gpa.deinit();
+    const allocator = gpa.allocator();
+
+    std.debug.print("\n╔═══════════════════════════════════════════════════╗\n", .{});
+    std.debug.print("║  BNNS ANE vs Metal BF16 GPU Benchmark            ║\n", .{});
+    std.debug.print("╚═══════════════════════════════════════════════════╝\n\n", .{});
+
+    const m: u32 = 1;
+    const k: u32 = 5120;
+    const n: u32 = 5120;
+    const iterations: u32 = 10;
+
+    std.debug.print("Matrix: [{}, {}] × [{}, {}] = [{}, {}]\n", .{ m, k, k, n, m, n });
+    std.debug.print("Iterations: {}\n", .{iterations});
+    std.debug.print("FLOPs per matmul: {} million\n\n", .{2 * m * k * n / 1_000_000});
+
+    // Allocate test data
+    const a = try allocator.alloc(BF16, m * k);
+    defer allocator.free(a);
+    const b = try allocator.alloc(BF16, k * n);
+    defer allocator.free(b);
+    const c_bnns = try allocator.alloc(BF16, m * n);
+    defer allocator.free(c_bnns);
+    const c_metal = try allocator.alloc(BF16, m * n);
+    defer allocator.free(c_metal);
+
+    @memset(a, 0x3F80); // 1.0
+    @memset(b, 0x3F80); // 1.0
+
+    // ═══════════════════════════════════════════════════════════════
+    // Benchmark 1: BNNS ANE
+    // ═══════════════════════════════════════════════════════════════
+    std.debug.print("═══════════════════════════════════════════════════════\n", .{});
+    std.debug.print("Benchmark 1: BNNS ANE (Neural Engine, low power)\n", .{});
+    std.debug.print("═══════════════════════════════════════════════════════\n\n", .{});
+
+    var bnns_engine = try bnns_ane.BNNSANEMatmulEngine.init(allocator);
+    defer bnns_engine.deinit();
+
+    var bnns_total: i128 = 0;
+    var i: u32 = 0;
+    while (i < iterations) : (i += 1) {
+        const start = std.time.nanoTimestamp();
+        try bnns_engine.matmul(a, b, c_bnns, m, k, n);
+        const end = std.time.nanoTimestamp();
+        bnns_total += (end - start);
+
+        if ((i + 1) % 5 == 0) {
+            const avg = @as(f64, @floatFromInt(bnns_total)) / @as(f64, @floatFromInt(i + 1)) / 1_000_000.0;
+            std.debug.print("  Completed {}/{} (avg: {d:.2}ms)\n", .{ i + 1, iterations, avg });
+        }
+    }
+
+    const bnns_avg_ms = @as(f64, @floatFromInt(bnns_total)) / @as(f64, @floatFromInt(iterations)) / 1_000_000.0;
+    const bnns_gflops = (@as(f64, 2 * m * k * n) / 1_000_000_000.0) / (bnns_avg_ms / 1000.0);
+
+    std.debug.print("\nAverage: {d:.2}ms per matmul\n", .{bnns_avg_ms});
+    std.debug.print("Performance: {d:.2} GFLOPS\n\n", .{bnns_gflops});
+
+    // ═══════════════════════════════════════════════════════════════
+    // Benchmark 2: Metal BF16 GPU
+    // ═══════════════════════════════════════════════════════════════
+    std.debug.print("═══════════════════════════════════════════════════════\n", .{});
+    std.debug.print("Benchmark 2: Metal BF16 GPU (high performance)\n", .{});
+    std.debug.print("═══════════════════════════════════════════════════════\n\n", .{});
+
+    const device = objc.createSystemDefaultDevice() orelse return error.MetalDeviceNotFound;
+    const queue = objc.deviceNewCommandQueue(device) orelse return error.CommandQueueFailed;
+
+    var metal_engine = try metal_bf16.MetalBF16MatmulEngine.init(allocator, device, queue);
+    defer metal_engine.deinit();
+
+    var metal_total: i128 = 0;
+    i = 0;
+    while (i < iterations) : (i += 1) {
+        const start = std.time.nanoTimestamp();
+        try metal_engine.matmul(a, b, c_metal, m, k, n);
+        const end = std.time.nanoTimestamp();
+        metal_total += (end - start);
+
+        if ((i + 1) % 5 == 0) {
+            const avg = @as(f64, @floatFromInt(metal_total)) / @as(f64, @floatFromInt(i + 1)) / 1_000_000.0;
+            std.debug.print("  Completed {}/{} (avg: {d:.2}ms)\n", .{ i + 1, iterations, avg });
+        }
+    }
+
+    const metal_avg_ms = @as(f64, @floatFromInt(metal_total)) / @as(f64, @floatFromInt(iterations)) / 1_000_000.0;
+    const metal_gflops = (@as(f64, 2 * m * k * n) / 1_000_000_000.0) / (metal_avg_ms / 1000.0);
+
+    std.debug.print("\nAverage: {d:.2}ms per matmul\n", .{metal_avg_ms});
+    std.debug.print("Performance: {d:.2} GFLOPS\n\n", .{metal_gflops});
+
+    // ═══════════════════════════════════════════════════════════════
+    // Comparison
+    // ═══════════════════════════════════════════════════════════════
+    std.debug.print("═══════════════════════════════════════════════════════\n", .{});
+    std.debug.print("COMPARISON\n", .{});
+    std.debug.print("═══════════════════════════════════════════════════════\n\n", .{});
+
+    const speedup = bnns_avg_ms / metal_avg_ms;
+
+    std.debug.print("BNNS ANE:      {d:.2}ms  ({d:.2} GFLOPS)\n", .{ bnns_avg_ms, bnns_gflops });
+    std.debug.print("Metal BF16:    {d:.2}ms  ({d:.2} GFLOPS)  [{d:.1}x faster]\n\n", .{ metal_avg_ms, metal_gflops, speedup });
+
+    // Verify correctness
+    std.debug.print("Correctness check:\n", .{});
+    std.debug.print("  BNNS output[0]: {x:0>4}\n", .{c_bnns[0]});
+    std.debug.print("  Metal output[0]: {x:0>4}\n", .{c_metal[0]});
+    std.debug.print("  Expected: 0x1440 (5120.0)\n\n", .{});
+
+    if (c_bnns[0] == c_metal[0]) {
+        std.debug.print("✅ Both produce same output\n\n", .{});
+    } else {
+        std.debug.print("⚠️  Outputs differ slightly (expected with BF16)\n\n", .{});
+    }
+
+    std.debug.print("╔═══════════════════════════════════════════════════╗\n", .{});
+    std.debug.print("║  Recommendation:                                  ║\n", .{});
+    std.debug.print("║                                                   ║\n", .{});
+    if (speedup > 100.0) {
+        std.debug.print("║  ⚠️  BNNS is {d:.0}x SLOWER - not using ANE!     ║\n", .{speedup});
+        std.debug.print("║  Likely running on CPU, not Neural Engine       ║\n", .{});
+        std.debug.print("║  Stick with Metal BF16 GPU for now              ║\n", .{});
+    } else if (speedup > 5.0) {
+        std.debug.print("║  Metal BF16 is {d:.1}x faster                       ║\n", .{speedup});
+        std.debug.print("║  Use Metal for speed, BNNS for battery life     ║\n", .{});
+    } else {
+        std.debug.print("║  Performance is similar!                          ║\n", .{});
+        std.debug.print("║  BNNS uses less power - good for battery        ║\n", .{});
+    }
+    std.debug.print("║                                                   ║\n", .{});
+    std.debug.print("╚═══════════════════════════════════════════════════╝\n\n", .{});
+}

