+//! Working BNNS MatMul test with correct descriptor configuration
+
+const std = @import("std");
+const BF16 = @import("inference/gguf_loader.zig").BF16;
+
+// BNNS C API
+const c = struct {
+    pub const BNNSDataTypeFloat32: c_int = 0x10020;
+    pub const BNNSDataLayoutRowMajorMatrix: c_int = 1;
+
+    pub const BNNSNDArrayDescriptor = extern struct {
+        flags: u32,
+        layout: c_int,
+        size: [8]usize,
+        stride: [8]usize,
+        data: ?*anyopaque,
+        data_type: c_int,
+        table_data: ?*anyopaque,
+        table_data_type: c_int,
+        data_scale: f32,
+        data_bias: f32,
+    };
+
+    extern "c" fn BNNSMatMul(
+        transA: bool,
+        transB: bool,
+        alpha: f32,
+        inputA: *const BNNSNDArrayDescriptor,
+        inputB: *const BNNSNDArrayDescriptor,
+        output: *const BNNSNDArrayDescriptor,
+        workspace: ?*anyopaque,
+        filter_params: ?*const anyopaque,
+    ) c_int;
+};
+
+fn bf16ToF32(bf16: BF16) f32 {
+    const bits: u32 = @as(u32, bf16) << 16;
+    return @bitCast(bits);
+}
+
+fn f32ToBF16(f: f32) BF16 {
+    const bits: u32 = @bitCast(f);
+    const rounding_bias: u32 = 0x00007FFF + ((bits >> 16) & 1);
+    const rounded = bits + rounding_bias;
+    return @truncate(rounded >> 16);
+}
+
+pub fn main() !void {
+    var gpa = std.heap.GeneralPurposeAllocator(.{}){};
+    defer _ = gpa.deinit();
+    const allocator = gpa.allocator();
+
+    std.debug.print("\n=== BNNS MatMul Working Test ===\n\n", .{});
+
+    // Test: [1, 4] × [4, 3] = [1, 3]
+    const m: u32 = 1;
+    const k: u32 = 4;
+    const n: u32 = 3;
+
+    std.debug.print("Testing: [{}, {}] × [{}, {}] = [{}, {}]\n\n", .{ m, k, k, n, m, n });
+
+    // Allocate Float32 arrays (BNNS works well with Float32)
+    const a = try allocator.alloc(f32, m * k);
+    defer allocator.free(a);
+    const b = try allocator.alloc(f32, k * n);
+    defer allocator.free(b);
+    const c_out = try allocator.alloc(f32, m * n);
+    defer allocator.free(c_out);
+
+    // Fill with 1.0
+    @memset(a, 1.0);
+    @memset(b, 1.0);
+    @memset(c_out, 0.0);
+
+    std.debug.print("Input A: ", .{});
+    for (a) |val| std.debug.print("{d:.1} ", .{val});
+    std.debug.print("\n", .{});
+
+    std.debug.print("Input B (first row): ", .{});
+    for (b[0..n]) |val| std.debug.print("{d:.1} ", .{val});
+    std.debug.print("\n\n", .{});
+
+    // Create correct descriptors (key insight from C test!)
+    // For row-major matrix [rows, cols]:
+    // - size[0] = cols, size[1] = rows
+    // - stride[0] = 1 (column stride), stride[1] = cols (row stride)
+
+    // Print debug info
+    std.debug.print("Matrix shapes:\n", .{});
+    std.debug.print("  A: [{}, {}] (m={}, k={})\n", .{ m, k, m, k });
+    std.debug.print("  B: [{}, {}] (k={}, n={})\n", .{ k, n, k, n });
+    std.debug.print("  C: [{}, {}] (m={}, n={})\n\n", .{ m, n, m, n });
+
+    var a_desc = c.BNNSNDArrayDescriptor{
+        .flags = 0,
+        .layout = c.BNNSDataLayoutRowMajorMatrix,
+        .size = .{ k, m, 0, 0, 0, 0, 0, 0 }, // [cols=4, rows=1]
+        .stride = .{ 1, k, 0, 0, 0, 0, 0, 0 }, // [col_stride=1, row_stride=4]
+        .data = @ptrCast(a.ptr),
+        .data_type = c.BNNSDataTypeFloat32,
+        .table_data = null,
+        .table_data_type = 0,
+        .data_scale = 1.0,
+        .data_bias = 0.0,
+    };
+
+    var b_desc = c.BNNSNDArrayDescriptor{
+        .flags = 0,
+        .layout = c.BNNSDataLayoutRowMajorMatrix,
+        .size = .{ n, k, 0, 0, 0, 0, 0, 0 }, // [cols=3, rows=4]
